import numpy as np

def encoding_resources(n_data_points, encoding_type):
    n = n_data_points

    if encoding_type == 'basis':
        qubits = int(np.ceil(np.log2(n)))
        gates = qubits  # O(log N) X gates
    elif encoding_type == 'amplitude':
        qubits = int(np.ceil(np.log2(n)))
        gates = n  # O(N) for general state prep
    elif encoding_type == 'angle':
        qubits = n
        gates = n  # One rotation per feature
    else:
        raise ValueError(f'Unknown encoding: {encoding_type}')

    return {'qubits': qubits, 'gates': gates}

for encoding in ['basis', 'amplitude', 'angle']:
    print(f'\n{encoding.upper()} ENCODING:')
    for n in [4, 16, 64, 256]:
        res = encoding_resources(n, encoding)
        print(f'  N={n:3}: qubits={res["qubits"]:4}, gates={res["gates"]:5}')
